import{_ as t,o as i,c as a,ai as r}from"./chunks/framework.-fuqNImP.js";const h=JSON.parse('{"title":"Security Policy","description":"","frontmatter":{},"headers":[],"relativePath":"reference/security.md","filePath":"reference/security.md"}'),o={name:"reference/security.md"};function n(s,e,l,c,d,p){return i(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="security-policy" tabindex="-1">Security Policy <a class="header-anchor" href="#security-policy" aria-label="Permalink to &quot;Security Policy&quot;">​</a></h1><h2 id="supported-versions" tabindex="-1">Supported Versions <a class="header-anchor" href="#supported-versions" aria-label="Permalink to &quot;Supported Versions&quot;">​</a></h2><p>We actively maintain and provide security updates for the following versions:</p><table tabindex="0"><thead><tr><th>Version</th><th>Supported</th></tr></thead><tbody><tr><td>Latest</td><td>✅</td></tr><tr><td>&lt; 1.0</td><td>❌</td></tr></tbody></table><h2 id="reporting-a-vulnerability" tabindex="-1">Reporting a Vulnerability <a class="header-anchor" href="#reporting-a-vulnerability" aria-label="Permalink to &quot;Reporting a Vulnerability&quot;">​</a></h2><p>We take security seriously. If you discover a security vulnerability, please report it responsibly.</p><h3 id="how-to-report" tabindex="-1">How to Report <a class="header-anchor" href="#how-to-report" aria-label="Permalink to &quot;How to Report&quot;">​</a></h3><p><strong>DO NOT</strong> open a public GitHub issue for security vulnerabilities.</p><p>Instead, please email security concerns to: <strong><a href="https://github.com/tafreeman/midnight-automation-voyage/security/advisories/new" target="_blank" rel="noreferrer">Create a private security advisory on GitHub</a></strong></p><p>Or contact the maintainer directly at: <code>tafreeman [at] github</code></p><h3 id="what-to-include" tabindex="-1">What to Include <a class="header-anchor" href="#what-to-include" aria-label="Permalink to &quot;What to Include&quot;">​</a></h3><p>When reporting a vulnerability, please provide:</p><ol><li><strong>Description</strong> of the vulnerability</li><li><strong>Steps to reproduce</strong> the issue</li><li><strong>Potential impact</strong> and severity assessment</li><li><strong>Suggested fix</strong> if you have one</li><li><strong>Your contact information</strong> for follow-up</li></ol><h3 id="response-timeline" tabindex="-1">Response Timeline <a class="header-anchor" href="#response-timeline" aria-label="Permalink to &quot;Response Timeline&quot;">​</a></h3><ul><li><strong>Initial Response:</strong> Within 48 hours</li><li><strong>Status Update:</strong> Within 7 days</li><li><strong>Fix Timeline:</strong> Depends on severity <ul><li>Critical: 24-72 hours</li><li>High: 1-2 weeks</li><li>Medium: 2-4 weeks</li><li>Low: Next release cycle</li></ul></li></ul><h2 id="security-considerations" tabindex="-1">Security Considerations <a class="header-anchor" href="#security-considerations" aria-label="Permalink to &quot;Security Considerations&quot;">​</a></h2><h3 id="practice-app-security" tabindex="-1">Practice App Security <a class="header-anchor" href="#practice-app-security" aria-label="Permalink to &quot;Practice App Security&quot;">​</a></h3><p>The practice app (<code>practice-app/</code>) is <strong>intentionally vulnerable</strong> for educational purposes:</p><ul><li>Contains known bugs and edge cases for testing practice</li><li>Should <strong>never</strong> be deployed to production</li><li>Should <strong>only</strong> run locally or in isolated development environments</li><li>No real user data should ever be used with the practice app</li></ul><h3 id="training-app-security" tabindex="-1">Training App Security <a class="header-anchor" href="#training-app-security" aria-label="Permalink to &quot;Training App Security&quot;">​</a></h3><p>The training app (<code>training-app/</code>) is a static React application with:</p><ul><li>No backend or database</li><li>No user authentication</li><li>Progress stored in browser localStorage only</li><li>No external API calls</li><li>No collection of personal information</li></ul><h3 id="dependencies" tabindex="-1">Dependencies <a class="header-anchor" href="#dependencies" aria-label="Permalink to &quot;Dependencies&quot;">​</a></h3><p>We regularly:</p><ul><li>Update dependencies to patch known vulnerabilities</li><li>Monitor security advisories via GitHub Dependabot</li><li>Run security audits with <code>pnpm audit</code> and <code>npm audit</code></li></ul><h2 id="known-non-issues" tabindex="-1">Known Non-Issues <a class="header-anchor" href="#known-non-issues" aria-label="Permalink to &quot;Known Non-Issues&quot;">​</a></h2><p>The following are <strong>not</strong> security issues:</p><h3 id="intentional-practice-app-bugs" tabindex="-1">Intentional Practice App Bugs <a class="header-anchor" href="#intentional-practice-app-bugs" aria-label="Permalink to &quot;Intentional Practice App Bugs&quot;">​</a></h3><p>The practice app contains intentional bugs for learning purposes:</p><ul><li>Form validation issues</li><li>Race conditions in toast notifications</li><li>Stale state in admin panel</li><li>Missing accessibility attributes</li><li>These are documented features for testing practice</li></ul><h3 id="localstorage-usage" tabindex="-1">LocalStorage Usage <a class="header-anchor" href="#localstorage-usage" aria-label="Permalink to &quot;LocalStorage Usage&quot;">​</a></h3><p>The training app stores progress in browser localStorage:</p><ul><li>No sensitive data is stored</li><li>Data never leaves the user&#39;s browser</li><li>Users can clear it anytime via browser settings</li></ul><h3 id="development-server-exposure" tabindex="-1">Development Server Exposure <a class="header-anchor" href="#development-server-exposure" aria-label="Permalink to &quot;Development Server Exposure&quot;">​</a></h3><p>Development servers (<code>pnpm dev</code>) are meant for local use only:</p><ul><li>Default ports (5173, 5174) are not exposed publicly</li><li>No production deployment instructions for dev mode</li></ul><h2 id="security-best-practices" tabindex="-1">Security Best Practices <a class="header-anchor" href="#security-best-practices" aria-label="Permalink to &quot;Security Best Practices&quot;">​</a></h2><p>If you&#39;re using this platform for training:</p><ol><li><strong>Run locally only</strong> — don&#39;t expose dev servers to the internet</li><li><strong>Don&#39;t use real credentials</strong> — the practice app uses test accounts only</li><li><strong>Keep dependencies updated</strong> — run <code>pnpm update</code> regularly</li><li><strong>Review code changes</strong> — inspect PRs before deploying</li></ol><h2 id="third-party-integrations" tabindex="-1">Third-Party Integrations <a class="header-anchor" href="#third-party-integrations" aria-label="Permalink to &quot;Third-Party Integrations&quot;">​</a></h2><p>This platform integrates with:</p><table tabindex="0"><thead><tr><th>Service</th><th>Purpose</th><th>Data Shared</th></tr></thead><tbody><tr><td>GitHub (optional)</td><td>Repository cloning</td><td>None</td></tr><tr><td>GitHub Copilot (optional)</td><td>AI code generation</td><td>Code context only</td></tr><tr><td>Playwright</td><td>Test automation</td><td>None (runs locally)</td></tr></tbody></table><p><strong>No data is sent to external servers</strong> — all processing happens locally.</p><h2 id="responsible-disclosure" tabindex="-1">Responsible Disclosure <a class="header-anchor" href="#responsible-disclosure" aria-label="Permalink to &quot;Responsible Disclosure&quot;">​</a></h2><p>We follow coordinated vulnerability disclosure:</p><ol><li>Reporter notifies us privately</li><li>We confirm and develop a fix</li><li>We release the fix</li><li>Public disclosure after users have time to update</li></ol><p>We appreciate responsible disclosure and may publicly acknowledge reporters (with permission) in our security advisories.</p><h2 id="questions" tabindex="-1">Questions? <a class="header-anchor" href="#questions" aria-label="Permalink to &quot;Questions?&quot;">​</a></h2><p>For security-related questions that aren&#39;t vulnerabilities, you can:</p><ul><li><a href="https://github.com/tafreeman/midnight-automation-voyage/discussions" target="_blank" rel="noreferrer">Open a discussion</a></li><li>Email general questions to the maintainer</li></ul><p>Thank you for helping keep Midnight Automation Voyage secure!</p>',51)])])}const g=t(o,[["render",n]]);export{h as __pageData,g as default};
